/**
 * @summary Track complaint by ticket number (requires phone last-4)
 */
export const getTrackComplaintUrl = (
  ticketNumber: string,
  params: TrackComplaintParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/v1/complaints/track/${ticketNumber}?${stringifiedParams}`
    : `/api/v1/complaints/track/${ticketNumber}`;
};

