/**
 * @summary List generation plants
 */
export const getGetPlantsUrl = (params?: GetPlantsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/v1/sector/plants?${stringifiedParams}`
    : `/api/v1/sector/plants`;
};

export const getPlants = async (
  params?: GetPlantsParams,
  options?: RequestInit,
): Promise<void> => {
  return customFetch<void>(getGetPlantsUrl(params), {
    ...options,
    method: "GET",
  });
};

